mapper.insert:
INSERT INTO APT_HO_TY (
    HO_TY_NO
    , APT_CMPLEX_NO
    , TY_NM
    , EXCLUSIVE_SIZE
    , ROOM_CNT
    , BATHROOM_CNT
    , IMAGE_FILE_NO
) VALUES (
    #{hoTyNo}
    ,#{aptCmplexNo}
    ,#{tyNm}
    ,#{exclusiveSize}
    ,#{roomCnt}
    ,#{bathroomCnt}
    ,#{imageFileNo}
)

mapper.update:
UPDATE APT_HO_TY
SET
    TY_NM = #{tyNm}
  ,EXCLUSIVE_SIZE = #{exclusiveSize}
  ,ROOM_CNT = #{roomCnt}
  ,BATHROOM_CNT = #{bathroomCnt}
  ,IMAGE_FILE_NO = #{imageFileNo}

WHERE HO_TY_NO = #{hoTyNo}

mapper.select:
SELECT NVL(
           MAX(
               TO_NUMBER(
                   REGEXP_SUBSTR(HO_TY_NO, '[^_]+$')
               )
           ),
           0
       ) + 1
FROM APT_HO_TY
WHERE APT_CMPLEX_NO = #{aptCmplexNo}
